import{_ as e,o,c as d,ag as r}from"./chunks/framework.HG0H2VLS.js";const u=JSON.parse('{"title":"FilterDropdowns — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/patterns/FilterDropdowns/FilterDropdowns.figma-notes.md","filePath":"public/demos/src/patterns/FilterDropdowns/FilterDropdowns.figma-notes.md"}'),i={name:"public/demos/src/patterns/FilterDropdowns/FilterDropdowns.figma-notes.md"};function a(s,t,n,c,l,p){return o(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="filterdropdowns-—-figma-notes" tabindex="-1">FilterDropdowns — Figma Notes <a class="header-anchor" href="#filterdropdowns-—-figma-notes" aria-label="Permalink to &quot;FilterDropdowns — Figma Notes&quot;">​</a></h1><h2 id="figma-node" tabindex="-1">Figma Node <a class="header-anchor" href="#figma-node" aria-label="Permalink to &quot;Figma Node&quot;">​</a></h2><ul><li>File: <code>Lus07xi8pPXLN87sQIyrEt</code> (Affino AI Design System)</li><li>Component set: <code>3039:5639</code> — &quot;FilterDropdowns&quot; — <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=3039-5639" target="_blank" rel="noreferrer">open in Figma</a></li><li>Tier: <code>Pattern</code> → built into <code>src/patterns/FilterDropdowns/</code></li></ul><p>The popover bodies that open from a FilterItem / the FilterBar. One shared shell — a bordered 320px card with a per-type body and a full-width <strong>Apply</strong> button — composes existing design-system components for each of 17 filter types.</p><h2 id="dependencies-composed" tabindex="-1">Dependencies (composed) <a class="header-anchor" href="#dependencies-composed" aria-label="Permalink to &quot;Dependencies (composed)&quot;">​</a></h2><ul><li><strong>Input</strong> (<code>78:2016</code>) — the &quot;Filter by X&quot; header label, and the select / search / date-operator fields (label + field + right icon).</li><li><strong>Checkbox</strong> (<code>2043:2985</code>) — Multi Select rows and the single Checkbox type.</li><li><strong>FilterDropdownItemGroup</strong> (<code>3032:18397</code>) + <strong>FilterDropdownItem</strong> (<code>3032:18152</code>) — the Select Options lists.</li><li><strong>FilterItem</strong> (<code>2972:1058</code>) — the empty/dashed chips in More Filters.</li><li><strong>DatePicker</strong> (<code>3039:8761</code>) — the date operand fields (Date Range / Date Equal To), as popover triggers.</li><li><strong>Button</strong> (<code>53:2489</code>) — the primary Apply button (full-width).</li></ul><h2 id="variant-matrix-17-type-values" tabindex="-1">Variant matrix (17 Type values) <a class="header-anchor" href="#variant-matrix-17-type-values" aria-label="Permalink to &quot;Variant matrix (17 Type values)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Node ID</th><th>Type</th><th>Body composition</th><th>Built</th></tr></thead><tbody><tr><td>3039:5627</td><td>Select</td><td><em>consolidated</em> → shown as Select Options (see below)</td><td>🔁</td></tr><tr><td>3039:5632</td><td>w/Placeholder</td><td><em>consolidated</em> → shown as Select Options (see below)</td><td>🔁</td></tr><tr><td>3039:5633</td><td>Text</td><td>Input (text)</td><td>✅</td></tr><tr><td>3039:5626</td><td>Checkbox</td><td>title + single Checkbox</td><td>✅</td></tr><tr><td>3039:5629</td><td>Multi Select</td><td>label + Checkbox list (gap-5, max-h 384px)</td><td>✅</td></tr><tr><td>3039:5623</td><td>Multi Select w/search</td><td>Input (search) + scrolling Checkbox list</td><td>✅</td></tr><tr><td>3039:5634</td><td>Select Options</td><td>Input (chevron) + FilterDropdownItemGroup, <strong>no Apply</strong> (open state)</td><td>✅</td></tr><tr><td>3039:5628</td><td>Select Options w/subtext</td><td>Input (chevron) + FilterDropdownItemGroup (subtext), <strong>no Apply</strong></td><td>✅</td></tr><tr><td>3039:5636</td><td>Date In the last</td><td>Input (operator) + [number + unit select]</td><td>✅</td></tr><tr><td>3039:5635</td><td>Date Range</td><td>Input (operator) + [DatePicker &quot;and&quot; DatePicker]</td><td>✅</td></tr><tr><td>3039:5631</td><td>Date Equal To</td><td>Input (operator) + corner + DatePicker</td><td>✅</td></tr><tr><td>3039:5637</td><td>More Filters</td><td>FilterItem empty/rounded chips (no Apply)</td><td>✅</td></tr><tr><td>3039:5638</td><td>Predictive Text</td><td>Input + predictive suggestions</td><td>⏳ phase 2</td></tr><tr><td>3039:5625</td><td>Predictive Text Options</td><td>Input + option list</td><td>⏳ phase 2</td></tr><tr><td>3039:5622</td><td>Predictive text Options w/subtext</td><td>Input + option list (subtext)</td><td>⏳ phase 2</td></tr><tr><td>3039:5624</td><td>Multi Select Table</td><td>Datatables + checkboxes</td><td>⏳ phase 2</td></tr><tr><td>3039:5630</td><td>Multi Select Modal</td><td>Modal + Datatables + FilterItem chips</td><td>⏳ phase 2</td></tr></tbody></table><p><strong>Select consolidation (user direction, 2026-07-07):</strong> the plain <code>Select</code> and <code>w/Placeholder</code> variants are NOT shown as standalone panels. Per the reference, the Select is represented as <strong>two versions of its open state</strong> — the select field + the <code>FilterDropdownItemGroup</code> dropping below it, one without sub text (<code>Select Options</code>) and one with (<code>Select Options w/subtext</code>). These two omit the Apply button: choosing an option is the action.</p><p><strong>Phase 2 pending (per user, &quot;phased — core first&quot;):</strong> the three Predictive types, Multi Select Table, and Multi Select Modal. Their design contexts were NOT fetched yet and must be fetched from Figma before building (Predictive likely composes Input + FilterDropdownItemGroup; Table composes Datatables; Modal composes the Modal pattern).</p><h2 id="interaction-confirmed-with-user-2026-07-07" tabindex="-1">Interaction (confirmed with user, 2026-07-07) <a class="header-anchor" href="#interaction-confirmed-with-user-2026-07-07" aria-label="Permalink to &quot;Interaction (confirmed with user, 2026-07-07)&quot;">​</a></h2><ul><li><strong>Functional, reusing child JS.</strong> Checkboxes toggle natively; Select Options items toggle via <code>FilterDropdownItem.js</code>; date fields open a <code>DatePicker</code> popover via <code>DatePicker.js</code>.</li><li>Pattern-owned glue (<code>FilterDropdowns.js</code>): live <strong>search-filtering</strong> of the checkbox list (Multi Select w/search); an <strong>Apply</strong> button that emits <code>filter-dropdowns:apply</code>; and the <strong>interactive Select</strong> — clicking the field trigger opens/closes the floating <code>FilterDropdownItemGroup</code> menu (chevron rotates). The Select Options menus are <strong>single-select</strong>: choosing an option clears the others, sets the field value, and closes the menu; clicking outside / Esc also closes. (The shared <code>FilterDropdownItem</code> component remains multi-select for the checkbox-style lists; single-select is enforced in the pattern glue for select menus only.)</li><li>The operator / unit selects (Date types) render as readonly Input-chevron fields — a real Select/menu can be wired by the consumer.</li></ul><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma element</th><th>CSS</th></tr></thead><tbody><tr><td>Card shell</td><td><code>.filter-dropdowns</code> (<code>--list</code> = wider gap + capped scrolling body for Multi Select types)</td></tr><tr><td>Standalone header title (Checkbox type)</td><td><code>.filter-dropdowns__title</code></td></tr><tr><td>Checkbox list</td><td><code>.filter-dropdowns__checklist</code> (scrolls under <code>--list</code>)</td></tr><tr><td>Single-checkbox body</td><td><code>.filter-dropdowns__checkbox-body</code></td></tr><tr><td>Date operand row</td><td><code>.filter-dropdowns__date-row</code></td></tr><tr><td>&quot;and&quot; separator</td><td><code>.filter-dropdowns__date-sep</code></td></tr><tr><td>Leading corner icon</td><td><code>.filter-dropdowns__date-corner</code> (Lucide <code>corner-down-right</code>, 20px)</td></tr><tr><td>More Filters chip wrap</td><td><code>.filter-dropdowns__facets</code></td></tr><tr><td>Apply</td><td><code>.btn.btn--primary.filter-dropdowns__apply</code> (full width)</td></tr><tr><td>Options popover</td><td><code>.filter-dropdown-item-group</code> (child component)</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Card bg / border / radius</td><td><code>--ai-surface-primary</code> / <code>--ai-border-secondary</code> (1px) / <code>--ai-radius-md</code></td></tr><tr><td>Card padding</td><td><code>--ai-spacing-4</code> (12px)</td></tr><tr><td>Card gap</td><td><code>--ai-spacing-3</code> (8px); <code>--ai-spacing-5</code> (16px) for <code>--list</code></td></tr><tr><td>Card shadow</td><td><code>--ai-shadow-md</code> (Figma <code>light/shadow-md</code>)</td></tr><tr><td>Card width</td><td><code>--ai-size-6</code> (320px); <code>--list</code> max-height <code>--ai-size-7</code> (384px)</td></tr><tr><td>Checklist gap / bottom pad</td><td><code>--ai-spacing-4</code> / <code>--ai-spacing-3</code></td></tr><tr><td>Date corner icon</td><td><code>--ai-icon-size-md</code> (20px), <code>--ai-icon-contrast</code></td></tr><tr><td>Header title / label</td><td><code>--ai-font-title</code> semibold <code>--ai-font-fixed-xs</code> (14px)</td></tr></tbody></table><h2 id="token-gaps-decisions" tabindex="-1">Token Gaps / Decisions <a class="header-anchor" href="#token-gaps-decisions" aria-label="Permalink to &quot;Token Gaps / Decisions&quot;">​</a></h2><ul><li><strong>No token gaps</strong> — every value maps to an existing <code>--ai-*</code> token.</li><li><strong>Radius binding quirk:</strong> Figma bound the card <code>border-radius</code> to <code>--ai-spacing-3</code> (8px). Used <code>--ai-radius-md</code> (same 8px, correct category) — consistent with FilterDropdownItem(Group).</li><li><strong>Shadow:</strong> Figma <code>light/shadow-md</code> (<code>0 3px 10px .1, 0 1px 4px .16</code>) → <code>--ai-shadow-md</code> (<code>0 2px 10px .1</code>) — the design-system&#39;s named md shadow; optical, within tolerance.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Icons (Lucide):</strong> <code>chevron-down</code> (select/unit fields), <code>search</code> (search field), <code>calendar</code> (date fields, via DatePicker), <code>corner-down-right</code> (indented operand rows), <code>plus</code>/<code>circle-check</code>/<code>check</code> come from FilterItem / FilterDropdownItem / Checkbox.</li><li><strong>Header = Input label:</strong> Figma composes the Input component for the &quot;Filter by X&quot; heading (label-only for Multi Select; label + field otherwise). Checkbox type uses a standalone <code>.filter-dropdowns__title</code> instead of an Input label.</li><li><strong>Width:</strong> all bodies are 320px (<code>--ai-size-6</code>) except the pending Table (671px) and Modal (960px) which will not fit this shell — they are separate layouts in phase 2.</li></ul>',20)])])}const g=e(i,[["render",a]]);export{u as __pageData,g as default};
